const patchB64="";
function sha(file){return crypto.createHash("sha256").update(fs.readFileSync(file)).digest("hex");}
function stateFor(expected){
  return Object.keys(expected).every(function(rel){
    const full=path.join(repo,rel),want=expected[rel];
    if(want===null)return !fs.existsSync(full);
    return fs.existsSync(full)&&sha(full)===want;
  });
}
if(!fs.existsSync(path.join(repo,".git"))){console.error("Refusing: not a Git working tree: "+repo);process.exit(2);}
if(stateFor(target)){console.log("Forge Phase 2 reaction hardening is already applied.");process.exit(0);}
const mismatches=[];
Object.keys(baseline).forEach(function(rel){
  const full=path.join(repo,rel),want=baseline[rel];
  if(want===null){if(fs.existsSync(full))mismatches.push(rel+" (expected absent)");return;}
  if(!fs.existsSync(full)){mismatches.push(rel+" (missing)");return;}
  const got=sha(full);if(got!==want)mismatches.push(rel+" (sha256 "+got+", expected "+want+")");
});
if(mismatches.length){
  console.error("Refusing to patch an unknown or already-edited baseline:\n- "+mismatches.join("\n- "));
  process.exit(3);
}
const dir=fs.mkdtempSync(path.join(os.tmpdir(),"forge-reaction-hardening-"));
const patchFile=path.join(dir,"forge-reaction-hardening.patch");
fs.writeFileSync(patchFile,Buffer.from(patchB64,"base64"));
function run(args){
  const r=cp.spawnSync("git",args,{cwd:repo,encoding:"utf8"});
  if(r.status!==0){console.error((r.stderr||r.stdout||"git apply failed").trim());fs.rmSync(dir,{recursive:true,force:true});process.exit(4);}
}
run(["apply","--check","--whitespace=nowarn",patchFile]);
run(["apply","--whitespace=nowarn",patchFile]);
if(!stateFor(target)){console.error("Patch applied but target hashes did not verify.");fs.rmSync(dir,{recursive:true,force:true});process.exit(5);}
fs.rmSync(dir,{recursive:true,force:true});
console.log("Applied Forge Phase 2 reaction hardening to "+repo);
console.log("Changed files:\n- "+Object.keys(target).join("\n- "));
